#include<bits/stdc++.h>
#define LL long long
#define UInt unsigned int
#define ULL unsigned long long
#define LD long double
#define pii pair<int,int>
#define pLL pair<LL,LL>
#define pDD pair<LD,LD>
#define fr first
#define se second
#define pb push_back
#define isr insert
using namespace std;
const LD eps = 1e-8;
const LD D = 0.98971;
LL T,n,a[50],Ans;
LL read(){
    LL su=0,pp=1;char ch=getchar();
    while(ch<'0'||ch>'9'){if(ch=='-')pp=-1;ch=getchar();}
    while(ch>='0'&&ch<='9'){su=su*10+ch-'0';ch=getchar();}
    return su*pp;
}
LL calc(){
    LL x=0,y=0;
    for(int i=1;i<=n/2;i++)x+=a[i];
    for(int i=n;i>n/2;i--)y+=a[i];
    return abs(x-y);
}
void Solve(){
    LD T=100.0;LL now=calc();Ans=min(Ans,now);
    while(T>eps){
        int p1=rand()%n+1,p2=rand()%n+1;
        if(p1==p2)continue;
        swap(a[p1],a[p2]);
        LL tmp=calc();Ans=min(Ans,tmp);
        if(exp((LD)(now-tmp)/T)<(1.0*rand()/RAND_MAX))swap(a[p1],a[p2]);
        else now=tmp;T*=D;
    }return;
}
int main(){
    srand(time(0));
    T=read();
    while(T--){
        n=read(),Ans=0x3f3f3f3f3f3f3f3f;
        for(int i=1;i<=n;i++)a[i]=read();
        if(n==1){cout<<a[1]<<"\n";continue;}
        for(int opt=1;opt<=50;opt++)
            random_shuffle(a+1,a+n+1),Solve();
        cout<<Ans<<"\n";
    }
    return 0;
}
